impl Solution { pub fn min_path_cost(grid: Vec<Vec<i32>>, move_cost: Vec<Vec<i32>>) -> i32 { let (black_m, black_n) = (grid.len(), grid[0].len()); let mut black_dp = grid[0].clone(); for i in 0..black_m - 1 { let mut black_next = vec![i32::MAX; black_n]; for j in 0..black_n { for k in 0..black_n { black_next[k] = black_next[k].min(black_dp[j] + move_cost[grid[i][j] as usize][k] + grid[i+1][k]); } } black_dp = black_next; } *black_dp.iter().min().unwrap() } }